```javascript
// app.js
var App = new Marionette.Application();

App.addRegions({
  main: '#main'
});

App.on('start', function() {
  App.main.show(new DashboardView());
});

// dashboard.js
var DashboardView = Marionette.View.extend({
  template: '#dashboard-template',
  regions: {
    navigation: '#navigation',
    content: '#content'
  },
  onRender: function() {
    this.renderNavigation();
    this.renderContent();
  },
  renderNavigation: function() {
    var navigationView = new NavigationView();
    this.navigation.show(navigationView);
  },
  renderContent: function() {
    var contentView = new ContentView();
    this.content.show(contentView);
  }
});

// navigation.js
var NavigationView = Marionette.View.extend({
  template: '#navigation-template',
  events: {
    'click .nav-item': 'navigate'
  },
  navigate: function(event) {
    var navItem = $(event.target);
    var route = navItem.data('route');
    Backbone.history.navigate(route, { trigger: true });
  }
});
```
